const body = $input.first().json.body || $input.first().json;

const user_id              = body.user_id              || null;
const business_name        = body.business_name        || null;
const niche                = body.niche                || null;
const target_customer      = body.target_customer      || null;
const primary_goal         = body.primary_goal         || null;
const monthly_revenue_range = body.monthly_revenue_range || null;
const biggest_challenge    = body.biggest_challenge    || null;
const website_url          = body.website_url          || null;

// Required field validation
const required = { user_id, business_name, niche, target_customer, primary_goal, monthly_revenue_range, biggest_challenge };
const missing = Object.entries(required)
  .filter(([_, v]) => !v)
  .map(([k]) => k);

if (missing.length > 0) {
  throw new Error(`Missing required fields: ${missing.join(', ')}`);
}

// Sanitise website_url if provided
let sanitised_url = null;
if (website_url) {
  const trimmed = website_url.trim();
  sanitised_url = trimmed.startsWith('http') ? trimmed : `https://${trimmed}`;
}

// Validate monthly_revenue_range is a recognised band
const validRevenueBands = [
  '$0',
  '$0-$1k',
  '$1k-$5k',
  '$5k-$10k',
  '$10k-$25k',
  '$25k-$50k',
  '$50k-$100k',
  '$100k+'
];

const revenue_normalised = validRevenueBands.find(
  b => b.toLowerCase() === monthly_revenue_range.toLowerCase()
) || monthly_revenue_range;

return [{
  json: {
    user_id,
    business_name:         business_name.trim(),
    niche:                 niche.trim(),
    target_customer:       target_customer.trim(),
    primary_goal:          primary_goal.trim(),
    monthly_revenue_range: revenue_normalised,
    biggest_challenge:     biggest_challenge.trim(),
    website_url:           sanitised_url,
    now: new Date().toISOString()
  }
}];

// Collect both parallel branch outputs and validate before proceeding
const items = $input.all();
const origin = $('Parse & Validate').first().json;

if (!items || items.length === 0) {
  throw new Error('No results returned from parallel Supabase writes');
}

return [{
  json: {
    user_id:              origin.user_id,
    business_name:        origin.business_name,
    niche:                origin.niche,
    target_customer:      origin.target_customer,
    primary_goal:         origin.primary_goal,
    monthly_revenue_range: origin.monthly_revenue_range,
    biggest_challenge:    origin.biggest_challenge,
    website_url:          origin.website_url,
    now:                  origin.now,
    writes_completed:     items.length
  }
}];

