const triggerResult = $input.first().json;
const origin = $('Merge Parallel Writes').first().json;

// AI Profile Builder runs async — we don't block on its result
// Just capture whether it was reachable
const ai_builder_triggered = !triggerResult?.error;

return [{
  json: {
    ...origin,
    ai_builder_triggered
  }
}];

